1047→// Type-aware mutation operators
1048→// ---------------------------------------------------------------------------
1049→
1050→/// Mutate a single JSON value according to its type.
1051→///
1052→/// Applies a random type-appropriate mutation operator. The output is always
1053→/// type-valid for the given `TypeInfo`. Types that cannot be meaningfully
1054→/// mutated (Complex, Opaque, Unknown) are returned unchanged.
1055→pub fn mutate_value(value: &Value, typ: &TypeInfo, dictionary: &[&str], rng: &mut impl Rng) -> Value {
1056→    match typ {
1057→        TypeInfo::Int => mutate_int(value, rng),
1058→        TypeInfo::Float => mutate_float(value, rng),
1059→        TypeInfo::Bool => mutate_bool(value),
1060→        TypeInfo::Str => mutate_string(value, dictionary, rng),
1061→        TypeInfo::Array { element } => mutate_array(value, element, dictionary, rng),
1062→        TypeInfo::Object { fields } => mutate_object(value, fields, dictionary, rng),
1063→        TypeInfo::Union { variants } => mutate_union(value, variants, dictionary, rng),
1064→        TypeInfo::Nullable { inner } => mutate_nullable(value, inner, dictionary, rng),
1065→        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => value.clone(),
1066→    }
1067→}
1068→
1069→/// Mutate an input vector with per-field probability.
1070→///
1071→/// For each parameter, with probability `mutation_rate` (0.0–1.0), applies
1072→/// `mutate_value`; otherwise keeps the original value unchanged.
1073→pub fn mutate_inputs(
1074→    inputs: &[Value],
1075→    params: &[crate::types::ParamInfo],
1076→    mutation_rate: f64,
1077→    dictionary: &[&str],
1078→    rng: &mut impl Rng,
1079→) -> Vec<Value> {
1080→    inputs
1081→        .iter()
1082→        .zip(params.iter())
1083→        .map(|(val, param)| {
1084→            if rng.random_range(0.0..1.0_f64) < mutation_rate {
1085→                mutate_value(val, &param.typ, dictionary, rng)
1086→            } else {
1087→                val.clone()
1088→            }
1089→        })
1090→        .collect()
1091→}
1092→
1093→/// Mutate an integer value.
1094→fn mutate_int(value: &Value, rng: &mut impl Rng) -> Value {
1095→    let n = match value.as_i64() {
1096→        Some(n) => n,
1097→        None => return generate_int(rng),
1098→    };
1099→    let op: u8 = rng.random_range(0..3);
1100→    match op {
1101→        0 => {
1102→            // Small delta
1103→            let delta = rng.random_range(1..=10_i64);
1104→            if rng.random_bool(0.5) {
1105→                json!(n.saturating_add(delta))
1106→            } else {
1107→                json!(n.saturating_sub(delta))
1108→            }
1109→        }
1110→        1 => {
1111→            // Bitflip
1112→            let bit = rng.random_range(0..64_u32);
1113→            json!(n ^ (1_i64 << bit))
1114→        }
1115→        _ => {
1116→            // Boundary swap
1117→            let boundaries = [0_i64, i64::MIN, i64::MAX];
1118→            let idx = rng.random_range(0..boundaries.len());
1119→            json!(boundaries[idx])
1120→        }
1121→    }
1122→}
1123→
1124→/// Mutate a float value.
1125→fn mutate_float(value: &Value, rng: &mut impl Rng) -> Value {
1126→    let n = match value.as_f64() {
1127→        Some(n) => n,
1128→        None => return generate_float(rng),
1129→    };
1130→    let op: u8 = rng.random_range(0..4);
1131→    match op {
1132→        0 => {
1133→            // Epsilon perturbation
1134→            let factor = 1.0 + rng.random_range(-0.1..0.1_f64);
1135→            json!(n * factor)
1136→        }
1137→        1 => {
1138→            // Sign flip
1139→            json!(-n)
1140→        }
1141→        2 => {
1142→            // Special values — NaN becomes null in JSON, Inf becomes null too
1143→            let specials: &[f64] = &[f64::NAN, f64::INFINITY, f64::NEG_INFINITY, 0.0];
1144→            let idx = rng.random_range(0..specials.len());
1145→            json!(specials[idx])
1146→        }
1147→        _ => {
1148→            // Small delta
1149→            let delta = rng.random_range(-1.0..1.0_f64);
1150→            json!(n + delta)
1151→        }
1152→    }
1153→}
1154→
1155→/// Mutate a boolean value (always flip).
1156→fn mutate_bool(value: &Value) -> Value {
1157→    match value.as_bool() {
1158→        Some(b) => json!(!b),
1159→        None => json!(true),
1160→    }
1161→}
1162→
1163→/// Mutate a string value.
1164→///
1165→/// When `dictionary` is non-empty, an additional mutation operator (fragment
1166→/// injection) becomes available — it splices a random dictionary entry into
1167→/// the string at a random position.
1168→fn mutate_string(value: &Value, dictionary: &[&str], rng: &mut impl Rng) -> Value {
1169→    let s = match value.as_str() {
1170→        Some(s) => s.to_string(),
1171→        None => return generate_string(rng),
1172→    };
1173→    // 20% chance of structure-aware mutation (pattern insertion, unicode, segment ops)
1174→    if rng.random_range(0..5_u8) == 0 {
1175→        return json!(string_mutation::mutate_structure_aware(&s, rng));
1176→    }
1177→    let num_ops: u8 = if dictionary.is_empty() { 6 } else { 7 };
1178→    let op: u8 = rng.random_range(0..num_ops);
1179→    match op {
1180→        0 => {
1181→            // Char substitution
1182→            if s.is_empty() {
1183→                return json!(s);
1184→            }
1185→            let chars: Vec<char> = s.chars().collect();
1186→            let idx = rng.random_range(0..chars.len());
1187→            let new_char = rng.random_range(b' '..=b'~') as char;
1188→            let mut result: String = chars.iter().collect();
1189→            // Replace at byte position of the idx-th char
1190→            let byte_start: usize = chars[..idx].iter().map(|c| c.len_utf8()).sum();
1191→            let byte_end = byte_start + chars[idx].len_utf8();
1192→            result.replace_range(byte_start..byte_end, &new_char.to_string());
1193→            json!(result)
1194→        }
1195→        1 => {
1196→            // Char insertion
1197→            let chars: Vec<char> = s.chars().collect();
1198→            let idx = rng.random_range(0..=chars.len());
1199→            let new_char = rng.random_range(b' '..=b'~') as char;
1200→            let mut result = String::with_capacity(s.len() + 1);
1201→            for (i, ch) in chars.iter().enumerate() {
1202→                if i == idx {
1203→                    result.push(new_char);
1204→                }
1205→                result.push(*ch);
1206→            }
1207→            if idx == chars.len() {
1208→                result.push(new_char);
1209→            }
1210→            json!(result)
1211→        }
1212→        2 => {
1213→            // Char deletion
1214→            if s.is_empty() {
1215→                return json!(s);
1216→            }
1217→            let chars: Vec<char> = s.chars().collect();
1218→            let idx = rng.random_range(0..chars.len());
1219→            let result: String = chars
1220→                .iter()
1221→                .enumerate()
1222→                .filter(|(i, _)| *i != idx)
1223→                .map(|(_, c)| *c)
1224→                .collect();
1225→            json!(result)
1226→        }
1227→        3 => {
1228→            // Case flip
1229→            if s.is_empty() {
1230→                return json!(s);
1231→            }
1232→            let chars: Vec<char> = s.chars().collect();
1233→            let idx = rng.random_range(0..chars.len());
1234→            let result: String = chars
1235→                .iter()
1236→                .enumerate()
1237→                .map(|(i, c)| {
1238→                    if i == idx {
1239→                        if c.is_uppercase() {
1240→                            c.to_lowercase().next().unwrap_or(*c)
1241→                        } else {
1242→                            c.to_uppercase().next().unwrap_or(*c)
1243→                        }
1244→                    } else {
1245→                        *c
1246→                    }
1247→                })
1248→                .collect();
1249→            json!(result)
1250→        }
1251→        4 => {
1252→            // Empty
1253→            json!("")
1254→        }
1255→        5 => {
1256→            // Long string (1000 chars)
1257→            let long: String = (0..1000).map(|_| 'a').collect();
1258→            json!(long)
1259→        }
1260→        _ => {
1261→            // Dictionary fragment injection
1262→            let fragment = dictionary[rng.random_range(0..dictionary.len())];
1263→            let chars: Vec<char> = s.chars().collect();
1264→            let pos = rng.random_range(0..=chars.len());
1265→            let byte_pos: usize = chars[..pos].iter().map(|c| c.len_utf8()).sum();
1266→            let mut result = s;
1267→            result.insert_str(byte_pos, fragment);
1268→            json!(result)
1269→        }
1270→    }
1271→}
