1273→/// Mutate an array value.
1274→fn mutate_array(value: &Value, element: &TypeInfo, dictionary: &[&str], rng: &mut impl Rng) -> Value {
1275→    let arr = match value.as_array() {
1276→        Some(a) => a.clone(),
1277→        None => return generate_array(element, rng, None),
1278→    };
1279→    let op: u8 = if arr.is_empty() {
1280→        1 // Can only add
1281→    } else if arr.len() < 2 {
1282→        rng.random_range(0..3) // Remove, add, or mutate (no shuffle)
1283→    } else {
1284→        rng.random_range(0..4)
1285→    };
1286→    match op {
1287→        0 => {
1288→            // Remove element
1289→            let mut result = arr;
1290→            let idx = rng.random_range(0..result.len());
1291→            result.remove(idx);
1292→            json!(result)
1293→        }
1294→        1 => {
1295→            // Add element
1296→            let mut result = arr;
1297→            let new_elem = generate_random_value(element, rng, None);
1298→            result.push(new_elem);
1299→            json!(result)
1300→        }
1301→        2 => {
1302→            // Mutate element
1303→            let mut result = arr;
1304→            let idx = rng.random_range(0..result.len());
1305→            result[idx] = mutate_value(&result[idx], element, dictionary, rng);
1306→            json!(result)
1307→        }
1308→        _ => {
1309→            // Shuffle (swap two random elements)
1310→            let mut result = arr;
1311→            let i = rng.random_range(0..result.len());
1312→            let j = rng.random_range(0..result.len());
1313→            result.swap(i, j);
1314→            json!(result)
1315→        }
1316→    }
1317→}
1318→
1319→/// Mutate an object value.
1320→fn mutate_object(
1321→    value: &Value,
1322→    fields: &[(String, TypeInfo)],
1323→    dictionary: &[&str],
1324→    rng: &mut impl Rng,
1325→) -> Value {
1326→    let obj = match value.as_object() {
1327→        Some(o) => o.clone(),
1328→        None => return generate_object(fields, rng, None),
1329→    };
1330→    if fields.is_empty() {
1331→        return Value::Object(obj);
1332→    }
1333→    let op: u8 = rng.random_range(0..3);
1334→    match op {
1335→        0 => {
1336→            // Mutate field value
1337→            let mut result = obj;
1338→            let idx = rng.random_range(0..fields.len());
1339→            let (name, typ) = &fields[idx];
1340→            if let Some(current) = result.get(name) {
1341→                let mutated = mutate_value(current, typ, dictionary, rng);
1342→                result.insert(name.clone(), mutated);
1343→            }
1344→            Value::Object(result)
1345→        }
1346→        1 => {
1347→            // Remove a field
1348→            let mut result = obj;
1349→            let idx = rng.random_range(0..fields.len());
1350→            result.remove(&fields[idx].0);
1351→            Value::Object(result)
1352→        }
1353→        _ => {
1354→            // Add an extra field
1355→            let mut result = obj;
1356→            result.insert("_extra".to_string(), generate_unknown(rng));
1357→            Value::Object(result)
1358→        }
1359→    }
1360→}
1361→
1362→/// Mutate a union value by applying mutation with a random variant's type.
1363→fn mutate_union(value: &Value, variants: &[TypeInfo], dictionary: &[&str], rng: &mut impl Rng) -> Value {
1364→    if variants.is_empty() {
1365→        return value.clone();
1366→    }
1367→    let idx = rng.random_range(0..variants.len());
1368→    mutate_value(value, &variants[idx], dictionary, rng)
1369→}
1370→
1371→/// Mutate a nullable value: 20% chance to flip null/non-null, otherwise mutate inner.
1372→fn mutate_nullable(value: &Value, inner: &TypeInfo, dictionary: &[&str], rng: &mut impl Rng) -> Value {
1373→    if rng.random_range(0..5) == 0 {
1374→        // Flip null / non-null
1375→        if value.is_null() {
1376→            generate_random_value(inner, rng, None)
1377→        } else {
1378→            Value::Null
1379→        }
1380→    } else if value.is_null() {
1381→        // Stay null most of the time if already null
1382→        Value::Null
1383→    } else {
1384→        mutate_value(value, inner, dictionary, rng)
1385→    }
1386→}
