  1→//! Recursive function testing via iterative deepening with behavior map bootstrapping.
  2→//!
  3→//! Self-recursive functions are tested by:
  4→//! 1. Probing with small/boundary values to discover base-case behaviors
  5→//! 2. Mocking self-calls using known behaviors and deepening iteratively
  6→//! 3. Stopping when coverage stabilizes or max depth is reached
  7→
  8→use std::collections::{HashMap, HashSet};
  9→
 10→use serde_json::{json, Value};
 11→
 12→use crate::behavior::BehaviorMap;
 13→use crate::execution_record::ExecutionRecord;
 14→use crate::frontend::{Frontend, FrontendError};
 15→use crate::protocol::{
 16→    Command as ProtoCommand, FunctionAnalysis, MockBehavior, MockConfig, ResponseResult,
 17→};
 18→use crate::types::TypeInfo;
 19→
 20→/// Default maximum deepening depth for recursive function exploration.
 21→pub const DEFAULT_MAX_DEPTH: u32 = 10;
 22→
 23→/// Configuration for recursive function exploration.
 24→#[derive(Debug, Clone)]
 25→pub struct RecursiveConfig {
 26→    /// Maximum deepening iterations before stopping.
 27→    pub max_depth: u32,
 28→    /// Maximum probe executions for base-case discovery.
 29→    pub max_probes: usize,
 30→}
 31→
 32→impl Default for RecursiveConfig {
 33→    fn default() -> Self {
 34→        Self {
 35→            max_depth: DEFAULT_MAX_DEPTH,
 36→            max_probes: 20,
 37→        }
 38→    }
 39→}
 40→
 41→/// Result of exploring a self-recursive function.
 42→#[derive(Debug)]
 43→pub struct RecursiveResult {
 44→    pub function_name: String,
 45→    pub behavior_map: BehaviorMap,
 46→    /// Depth at which coverage stabilized (or max_depth if it didn't).
 47→    pub depth_reached: u32,
 48→    /// Number of base-case behaviors found via probing.
 49→    pub base_case_count: usize,
 50→    /// Total probe executions performed.
 51→    pub probes_executed: usize,
 52→}
 53→
 54→/// Errors during recursive exploration.
 55→#[derive(Debug, thiserror::Error)]
 56→pub enum RecursiveError {
 57→    #[error("frontend error: {0}")]
 58→    Frontend(#[from] FrontendError),
 59→    #[error("unexpected response from frontend: {0}")]
 60→    UnexpectedResponse(String),
 61→    #[error("no base cases found after probing")]
 62→    NoBaseCases,
 63→}
 64→
 65→/// Generate canonical probe values for a type.
 66→///
 67→/// Returns small/boundary values likely to trigger base cases in recursive
 68→/// functions (e.g., 0, 1, -1 for numbers; "" for strings; [] for arrays).
 69→fn probe_values(typ: &TypeInfo) -> Vec<Value> {
 70→    match typ {
 71→        TypeInfo::Int => vec![json!(0), json!(1), json!(-1), json!(2)],
 72→        TypeInfo::Float => vec![json!(0.0), json!(1.0), json!(-1.0), json!(0.5)],
 73→        TypeInfo::Str => vec![json!(""), json!("a")],
 74→        TypeInfo::Bool => vec![json!(false), json!(true)],
 75→        TypeInfo::Array { .. } => vec![json!([]), json!([1])],
 76→        TypeInfo::Object { fields } => {
 77→            // Single probe: object with minimal field values
 78→            let mut obj = serde_json::Map::new();
 79→            for (name, field_typ) in fields {
 80→                let vals = probe_values(field_typ);
 81→                if let Some(v) = vals.into_iter().next() {
 82→                    obj.insert(name.clone(), v);
 83→                }
 84→            }
 85→            vec![Value::Object(obj)]
 86→        }
 87→        TypeInfo::Union { variants } => {
 88→            // Probe values from each variant
 89→            variants.iter().flat_map(probe_values).collect()
 90→        }
 91→        TypeInfo::Nullable { inner } => {
 92→            let mut vals = vec![Value::Null];
 93→            vals.extend(probe_values(inner));
 94→            vals
 95→        }
 96→        // Complex types use same probes as Unknown for now
 97→        TypeInfo::Complex { .. } => vec![json!(0), json!(1), json!(-1), json!(""), json!(null)],
 98→        // Opaque types cannot be constructed; use same fallback probes as Unknown
 99→        TypeInfo::Opaque { .. } => vec![json!(0), json!(1), json!(-1), json!(""), json!(null)],
100→        TypeInfo::Unknown => vec![json!(0), json!(1), json!(-1), json!(""), json!(null)],
101→    }
102→}
103→
104→/// Generate combinatorial probe inputs for a function, capped at `max_probes`.
105→///
106→/// For single-parameter functions, returns probe values directly.
107→/// For multi-parameter functions, takes the cartesian product, capped.
108→fn generate_probe_inputs(params: &[crate::types::ParamInfo], max_probes: usize) -> Vec<Vec<Value>> {
109→    if params.is_empty() {
110→        return vec![vec![]];
111→    }
112→
113→    let per_param: Vec<Vec<Value>> = params.iter().map(|p| probe_values(&p.typ)).collect();
114→
115→    // Cartesian product with budget cap
116→    let mut results: Vec<Vec<Value>> = vec![vec![]];
117→    for param_vals in &per_param {
118→        let mut next = Vec::new();
119→        for existing in &results {
120→            for val in param_vals {
121→                if next.len() >= max_probes {
122→                    return next;
123→                }
124→                let mut combo = existing.clone();
125→                combo.push(val.clone());
126→                next.push(combo);
127→            }
128→        }
129→        results = next;
130→    }
131→
132→    results
133→}
134→
135→/// Probe a self-recursive function with small values to find base cases.
136→///
137→/// Executes the function with no mocks. Executions that don't call the function
138→/// itself are base cases. Returns execution records for base-case executions.
139→async fn probe_for_base_cases(
140→    frontend: &mut Frontend,
141→    analysis: &FunctionAnalysis,
142→    config: &RecursiveConfig,
143→) -> Result<(Vec<ExecutionRecord>, usize), RecursiveError> {
144→    let probe_inputs = generate_probe_inputs(&analysis.params, config.max_probes);
145→    let mut base_cases = Vec::new();
146→    let mut probes_executed = 0;
147→
148→    for inputs in probe_inputs {
149→        probes_executed += 1;
150→
151→        let response = frontend
152→            .send(ProtoCommand::Execute {
153→                function: analysis.name.clone(),
154→                inputs: inputs.clone(),
155→                mocks: vec![],
156→                setup_context: None,
157→            })
158→            .await?;
159→
160→        let exec_result = match response.result {
161→            ResponseResult::Execute(result) => result,
162→            ResponseResult::Error { code, message, .. } => {
163→                return Err(RecursiveError::UnexpectedResponse(format!(
164→                    "execute error ({code:?}): {message}"
165→                )));
166→            }
167→            other => {
168→                return Err(RecursiveError::UnexpectedResponse(format!("{other:?}")));
169→            }
170→        };
171→
172→        // A base case: the function didn't call itself
173→        let calls_self = exec_result
174→            .calls_to_external
175→            .iter()
176→            .any(|c| c.symbol == analysis.name);
177→
178→        if !calls_self {
179→            let input_hash = hash_inputs(&inputs);
180→            base_cases.push(make_exec_record(&analysis.name, input_hash, inputs, &exec_result));
181→        }
182→    }
183→
184→    Ok((base_cases, probes_executed))
185→}
186→
187→/// Explore a self-recursive function by iterative deepening.
188→///
189→/// 1. Probe with small values to find base cases (depth 0).
190→/// 2. For each subsequent depth, mock self-calls using the BehaviorMap from
191→///    all previous depths and execute with random inputs.
192→/// 3. Stop when no new behaviors are discovered or max_depth is reached.
193→pub async fn explore_recursive(
194→    frontend: &mut Frontend,
195→    analysis: &FunctionAnalysis,
196→    config: &RecursiveConfig,
197→) -> Result<RecursiveResult, RecursiveError> {
198→    // Step 1: Probe for base cases
199→    let (base_records, probes_executed) =
200→        probe_for_base_cases(frontend, analysis, config).await?;
201→    let base_case_count = base_records.len();
202→
203→    if base_records.is_empty() {
204→        return Err(RecursiveError::NoBaseCases);
205→    }
206→
207→    let mut all_records = base_records;
208→    let mut depth: u32 = 0;
209→
210→    // Step 2: Iterative deepening
211→    for d in 1..=config.max_depth {
212→        depth = d;
213→        let current_map = BehaviorMap::from_records(&analysis.name, &all_records);
214→        let mock = MockConfig {
215→            symbol: analysis.name.clone(),
216→            return_values: current_map
217→                .behaviors
218→                .iter()
219→                .filter_map(|b| b.return_value.clone())
220→                .collect(),
221→            should_track_calls: true,
222→            default_behavior: MockBehavior::RepeatLast,
223→        };
224→
225→        // Generate inputs that are slightly larger than the probe values
226→        let depth_inputs = generate_depth_inputs(&analysis.params, d);
227→        let behavior_count_before = current_map.behaviors.len();
228→        let mut found_new = false;
229→
230→        let seen_hashes: HashSet<u64> = all_records.iter().map(|r| r.input_hash).collect();
231→
232→        for inputs in depth_inputs {
233→            let input_hash = hash_inputs(&inputs);
234→            if seen_hashes.contains(&input_hash) {
235→                continue;
236→            }
237→
238→            let response = frontend
239→                .send(ProtoCommand::Execute {
240→                    function: analysis.name.clone(),
241→                    inputs: inputs.clone(),
242→                    mocks: vec![mock.clone()],
243→                    setup_context: None,
244→                })
245→                .await?;
246→
247→            let exec_result = match response.result {
248→                ResponseResult::Execute(result) => result,
249→                ResponseResult::Error { .. } => continue,
250→                _ => continue,
251→            };
252→
253→            all_records.push(make_exec_record(&analysis.name, input_hash, inputs, &exec_result));
254→        }
255→
256→        let updated_map = BehaviorMap::from_records(&analysis.name, &all_records);
257→        if updated_map.behaviors.len() > behavior_count_before {
258→            found_new = true;
259→        }
260→
261→        if !found_new {
262→            break;
263→        }
264→    }
265→
266→    let behavior_map = BehaviorMap::from_records(&analysis.name, &all_records);
267→
268→    Ok(RecursiveResult {
269→        function_name: analysis.name.clone(),
270→        behavior_map,
271→        depth_reached: depth,
272→        base_case_count,
273→        probes_executed,
274→    })
275→}
276→
277→/// Generate inputs for a given deepening depth.
278→///
279→/// At depth d, generates values around d (e.g., d, d+1, d-1 for integers)
280→/// to explore one level deeper than the previous iteration.
281→fn generate_depth_inputs(params: &[crate::types::ParamInfo], depth: u32) -> Vec<Vec<Value>> {
282→    if params.is_empty() {
283→        return vec![vec![]];
284→    }
285→
286→    let d = depth as i64;
287→    let per_param: Vec<Vec<Value>> = params
288→        .iter()
289→        .map(|p| match &p.typ {
290→            TypeInfo::Int => vec![json!(d), json!(d + 1), json!(d + 2)],
291→            TypeInfo::Float => vec![json!(d as f64), json!((d + 1) as f64)],
292→            TypeInfo::Str => {
293→                vec![json!("a".repeat(depth as usize))]
294→            }
295→            TypeInfo::Array { element } => {
296→                // Array of length `depth` with minimal elements
297→                let elem = match element.as_ref() {
